d by date (2025)", "source_query": "hunter:baptist-boards", "meta": {"h": "baptist-boards", "src": "https://www.ibfi.us/missionaries/north-america/darrain-and-mari-coker", "import_source": "batch3_2.sql"}}, {"org_name": "Sean Lunday (BIMI)", "org_type": "individual", "website": "bimi.org/connect/2026Brazil.php", "city": null, "state": null, "summary": "South America Regional Director for BIMI with Amazon ministry | Field: South America / Brazil | Comms: 2026", "fit_score": 7, "fit_reason": "Leads BIMI Connect trips with 2026 Brazil mission trip scheduled", "source_query": "hunter:baptist-boards", "meta": {"h": "baptist-boards", "src": "https://www.bimi.org/connect/2026Brazil.php", "import_source": "batch3_2.sql"}}, {"org_name": "Mark Gerosin (BIMI)", "org_type": "individual", "website": "bimi.org/missionaries/GerosinM.php", "city": null, "state": null, "summary": "Church planting missionaries in Medellin since 2009 | Field: Colombia | Comms: 2026", "fit_score": 7, "fit_reason": "BIMI listed with contact info and hosting mission trips", "source_query": "hunter:baptist-boards", "meta": {"h": "baptist-boards", "src": "https://www.bimi.org/missionaries/GerosinM.php", "import_source": "batch3_2.sql"}}, {"org_name": "David & Shari Ogg (Ethnos360)", "org_type": "individual", "website": "blogs.ethnos360.org/david-ogg", "city": null, "state": null, "summary": "NT translation with Simbari people PNG, Mexico mission work | Field: Papua New Guinea / Mexico mission trips | Comms: February 16, 2026", "fit_score": 9, "fit_reason": "Multiple dated posts 2025-2026 (Feb 2026, Dec 2025, Aug 2025), active personal blog with giving page", "source_query": "hunter:blog-networks", "meta": {"h": "blog-networks", "src": "https://blogs.ethnos360.org/david-ogg/", "import_source": "batch3_2.sql"}}]'::jsonb)
  as x(org_name text, org_type text, website text, city text, state text,
       summary text, fit_score int, fit_reason text, source_query text, meta jsonb)),
-- Count how many existing rows (queue + pipeline) share each URL.
-- A URL on exactly one row is a person-specific page safe to dedup
-- against; a URL shared by many is a roster/platform page and must
-- NOT cause a skip, or we'd drop distinct people who list it.
existing_sites as (
  select site, count(*) as n from (
    select rtrim(lower(regexp_replace(website, '^https?://(www\.)?', '', 'i')), '/') as site
      from sales.scout_candidates where website is not null and btrim(website) <> ''
    union all
    select rtrim(lower(regexp_replace(website, '^https?://(www\.)?', '', 'i')), '/') as site
      from sales.leads where website is not null and btrim(website) <> ''
  ) w group by site)
insert into sales.scout_candidates
  (org_name, org_type, website, city, state, summary,
   fit_score, fit_reason, source_query, status, meta)
select s.org_name, s.org_type, s.website, s.city, s.state, s.summary,
       s.fit_score, s.fit_reason, s.source_query, 'pending', coalesce(s.meta, '{}'::jsonb)
from src s
where not exists (select 1 from sales.scout_candidates c
                  where lower(trim(c.org_name)) = lower(trim(s.org_name)))
  and not exists (select 1 from sales.leads l
                  where lower(trim(l.org_name)) = lower(trim(s.org_name)))
  and not exists (select 1 from existing_sites es
                  where s.website is not null and btrim(s.website) <> ''
                    and es.n = 1
                    and es.site = rtrim(lower(regexp_replace(s.website, '^https?://(www\.)?', '', 'i')), '/'));